import Navigation from '../components/Navigation';

const Menu = () => {
    return (
        <section>
            <Navigation />
            <main>
                <picture>
                    <h1>Menu</h1>
                    <h2>Yaki 1</h2>
                    <source srcSet="" sizes="
                                (max-width: 320px) 320px,
                                (max-width: 480px) 480px,
                                (max-width: 640px) 640px,
                                (max-width: 720px) 720px,
                                (max-width: 960px) 960px" media="(min-width: 320px)">
                        <img src="/" className="w-100 py-2" alt="yakitori"></img>
                    </source>
                </picture>
            </main>
        </section>
    );
};

export default Menu;
